    dashboard: {
      defaultLayout: ({ req }) => {
        // Customize layout based on user role or other factors
        const isAdmin = req.user?.roles?.includes('admin')

        return [
          { widgetSlug: 'collections', width: 'full' },
          {
            widgetSlug: 'sales-summary',
            data: {
              timeframe: 'monthly',
              title: 'Revenue Overview',
